#include<bits/stdc++.h>
using namespace std;
int l[100010],r[100010];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n,k;
        scanf("%d%d",&n,&k);
        int min1=1e9;
        for(int i=1;i<=n;i++)
        {
            scanf("%d%d",&l[i],&r[i]);
            min1=min(min1,r[i]-l[i]+1);
        }
        if(min1>=k)
        {
            printf("Yes\n");
            for(int i=1;i<=n;i++)
            {
                printf("%d ",(l[i]+k-1)/k*k);
            }
            printf("\n");
            continue;
        }
        int pos=-1;
        for(int i=1;i<=n;i++)
        {
            if(pos==-1||r[i]-l[i]+1<r[pos]-l[pos]+1)
            {
                pos=i;
            }
        }
        int f=0;
        set<int> s;
        s.clear();
        for(int i=l[pos];i<=r[pos];i++)
        {
            for(int j=1;j*j<=i;j++)
            {
                if(i%j==0)
                {
                    if(j>=k)
                    {
                        s.insert(j);
                    }
                    if(j!=i/j)
                    {
                        if(i/j>=k)
                        {
                            s.insert(i/j);
                        }
                    }
                }
            }
        }
        for(int j:s)
        {
            int flag=1;
            for(int p=1;p<=n;p++)
            {
                if((l[p]+j-1)/j*j>r[p])
                {
                    flag=0;
                    break;
                }
            }
            if(flag)
            {
                f=j;
                break;
            }
        }
        if(f)
        {
            printf("Yes\n");
            for(int i=1;i<=n;i++)
            {
                printf("%d ",(l[i]+f-1)/f*f);
            }
            printf("\n");
        }
        else
        {
            printf("No\n");
        }
    }
    return 0;
}
